import{_ as a,o as l,c as i,ae as o}from"./chunks/framework.EHGTsUvI.js";const c=JSON.parse('{"title":"什么是 Token 与上下文窗口：从 BPE 到成本控制","description":"","frontmatter":{},"headers":[],"relativePath":"ai-tutorial/what-is-token.md","filePath":"ai-tutorial/what-is-token.md"}'),t={name:"ai-tutorial/what-is-token.md"};function n(r,e,k,h,p,s){return l(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="什么是-token-与上下文窗口-从-bpe-到成本控制" tabindex="-1">什么是 Token 与上下文窗口：从 BPE 到成本控制 <a class="header-anchor" href="#什么是-token-与上下文窗口-从-bpe-到成本控制" aria-label="Permalink to &quot;什么是 Token 与上下文窗口：从 BPE 到成本控制&quot;">​</a></h1><blockquote><p>Token 这个词看上去像个基础概念，偏偏又是最容易把项目预算、延迟和上下文体验一起搅乱的那个基础概念。 很多团队第一次接入模型后，最先感受到的甚至不是“模型很聪明”，而是“怎么刚聊几轮，账单和长度限制就都开始给脸色看了”。真到这时，Token 就不再是术语，而是系统设计问题了。</p></blockquote><div class="info custom-block"><p class="custom-block-title">这篇文章重点</p><ul><li>Token 和字符、单词有什么区别</li><li>BPE 为什么会成为常见分词方式</li><li>为什么上下文窗口会直接影响成本和效果</li></ul></div><h2 id="_1-token-不是-一个字-也不是-一个单词" tabindex="-1">1. Token 不是“一个字”也不是“一个单词” <a class="header-anchor" href="#_1-token-不是-一个字-也不是-一个单词" aria-label="Permalink to &quot;1. Token 不是“一个字”也不是“一个单词”&quot;">​</a></h2><p>模型看到的输入并不是原始自然语言，而是被切分后的 Token 序列。</p><p>一个 Token 可能是：</p><ul><li>一个汉字</li><li>一个英文单词的一部分</li><li>一个标点</li><li>一段常见字符串片段</li></ul><p>所以字符数、单词数和 Token 数并不等价。</p><h2 id="_2-bpe-在解决什么问题" tabindex="-1">2. BPE 在解决什么问题 <a class="header-anchor" href="#_2-bpe-在解决什么问题" aria-label="Permalink to &quot;2. BPE 在解决什么问题&quot;">​</a></h2><p>像 BPE（Byte Pair Encoding）这类方法的目标，是在“切得太碎”和“词表太大”之间找到平衡。</p><p>它的价值在于：</p><ul><li>常见片段可以合并，提高效率</li><li>生僻词仍可拆分，避免完全 OOV</li></ul><p>这使得模型能更灵活地处理多语言和长尾表达。</p><h2 id="_3-为什么-token-直接影响成本" tabindex="-1">3. 为什么 Token 直接影响成本 <a class="header-anchor" href="#_3-为什么-token-直接影响成本" aria-label="Permalink to &quot;3. 为什么 Token 直接影响成本&quot;">​</a></h2><p>大多数模型服务的计费、延迟和上下文限制都与 Token 数有关。Token 越多，通常意味着：</p><ul><li>输入更贵</li><li>输出更贵</li><li>延迟更高</li><li>上下文更容易被占满</li></ul><p>所以在工程里，控制 Token 使用量不仅是省钱，也是在提高系统稳定性。</p><h2 id="_4-上下文窗口是什么" tabindex="-1">4. 上下文窗口是什么 <a class="header-anchor" href="#_4-上下文窗口是什么" aria-label="Permalink to &quot;4. 上下文窗口是什么&quot;">​</a></h2><p>上下文窗口可以理解为模型一次能“看到”的 Token 上限。它不是说模型真正理解了全部内容，而是：</p><ul><li>超过这个长度通常无法一次完整输入</li><li>越接近上限，成本和注意力负担越大</li></ul><p>因此长上下文并不等于随便塞。真正重要的是把最相关的信息放进去。</p><h2 id="_5-工程上怎么控制-token-成本" tabindex="-1">5. 工程上怎么控制 Token 成本 <a class="header-anchor" href="#_5-工程上怎么控制-token-成本" aria-label="Permalink to &quot;5. 工程上怎么控制 Token 成本&quot;">​</a></h2><p>常见做法包括：</p><ul><li>截断无关历史对话</li><li>对长文先摘要再送模型</li><li>检索时只组装高相关内容</li><li>在网关层估算和限制 Token</li></ul><h2 id="小结" tabindex="-1">小结 <a class="header-anchor" href="#小结" aria-label="Permalink to &quot;小结&quot;">​</a></h2><p>Token 是模型处理语言的基本单位。理解它，能帮助你更准确地判断：</p><ul><li>输入为什么这么长</li><li>成本为什么会上涨</li><li>上下文为什么会成为系统设计重点</li></ul><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><ul><li><a href="https://platform.openai.com/tokenizer" target="_blank" rel="noreferrer">OpenAI Tokenizer</a></li><li><a href="https://github.com/openai/tiktoken" target="_blank" rel="noreferrer">tiktoken</a></li><li>延伸阅读：<a href="./rag-intro.html">初探 RAG 架构</a></li></ul>',29)])])}const d=a(t,[["render",n]]);export{c as __pageData,d as default};
